#include<iostream>
#include<cstdio>
#include<algorithm>
#include<cstring>
#include<iomanip>
#include<climits>
#include<string>
#include<cctype>
#include<vector>
using namespace std;
int dp[2097152];
vector<int> mp[1010][1010];
vector<pair<int,int>> v;
int x[1010],y[1010],a[1010];
int dx[5]={0,0,-1,0,1};
int dy[5]={0,1,0,-1,0};
int query(int x,int p)
{
    int tmp=x;
    tmp>>=(p-1)*2;
    return tmp&3;
}
int set(int x,int p,int v)
{
    if(query(x,p)==v)
    {
        return x;
    }
    int base=(1<<((p-1)*2));
    int tmp=(x-(query(x,p)*base))+(v*base);
    return tmp;
}
int jian(int x,int p)
{
    if(query(x,p)==0)
    {
        return x;
    }
    return set(x,p,query(x,p)-1);
}
int main()
{
    int n,m,k;
    scanf("%d%d%d",&n,&m,&k);
    int s=0;
    for(int i=1;i<=k;i++)
    {
        scanf("%d%d%d",&x[i],&y[i],&a[i]);
        s=set(s,i,a[i]);
        for(int j=0;j<5;j++)
        {
            int xx=x[i]+dx[j],yy=y[i]+dy[j];
            if(xx<0||yy<0||xx>n||yy>m)
            {
                continue;
            }
            mp[xx][yy].push_back(i);
            v.push_back(make_pair(xx,yy));
        }
    }
    sort(v.begin(),v.end());
    unique(v.begin(),v.end());
    memset(dp,0x3f,sizeof(dp));
    dp[s]=0;
    for(int i=s;i>0;i--)
    {
        for(auto j:v)
        {
            int x=j.first,y=j.second,tmp=i;
            for(int k:mp[x][y])
            {
                tmp=jian(tmp,k);
            }
            dp[tmp]=min(dp[tmp],dp[i]+1);
        }
    }
    printf("%d",dp[0]);
    return 0;
}
